import{_ as p,c as e,o,ag as a}from"./chunks/framework.KLbWPeN7.js";const i="/images/be3600.png",r="/images/%E9%99%8D%E7%BA%A71.0.81.png",s="/images/uboot%E5%88%B7%E6%9C%BA.png",l="/images/%E7%B3%BB%E7%BB%9F%E7%8A%B6%E6%80%81.png",B=JSON.parse('{"title":"小米路由器BE3600-2.5G版，开箱刷openwrt详细教程","description":"","frontmatter":{},"headers":[],"relativePath":"flash-tutorials/mi-be3600.md","filePath":"flash-tutorials/mi-be3600.md"}'),m={name:"flash-tutorials/mi-be3600.md"};function b(n,t,d,u,h,c){return o(),e("div",null,t[0]||(t[0]=[a('<h1 id="小米路由器be3600-2-5g版-开箱刷openwrt详细教程" tabindex="-1">小米路由器BE3600-2.5G版，开箱刷openwrt详细教程 <a class="header-anchor" href="#小米路由器be3600-2-5g版-开箱刷openwrt详细教程" aria-label="Permalink to &quot;小米路由器BE3600-2.5G版，开箱刷openwrt详细教程&quot;">​</a></h1><ul><li>我从网上淘的一个小米路由器BE3600(2.5G版），80元包邮到手，自带系统版本1.0.87！其采用的是高通的IPQ5312，内存容量256MB，闪存容量128MB，算是入门级的Wi-Fi 7路由器了！</li><li>作为一台Wi-Fi7路由器，小米路由器BE3600 2.5G版（也有千兆版）支持了很多新东西，相比Wi-Fi 6E的160MHz，Wi-Fi7理论上可以达到的320MHz频宽直接翻了个倍。而且，在理论上，Wi-Fi 7的满血下传输速率可达46Gbps，而Wi-Fi 6E则只有9.6Gbps，翻了4.8倍。只是，目前支持320MHz的6GHz频段还没在国内开放，体验到满血版Wi-Fi 7还需要再等等。所以，你现在只能在小米路由器BE3600 2.5G版上用到最高160MHz频宽。其他缺点高通的芯片openwrt固件适配慢，还少，不如联发科芯片牛逼！好下面开始刷机!</li></ul><h2 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h2><ul><li>小米BE3600路由器一台</li><li>准备一跟网线，一台windows系统电脑。</li><li>下载刷机工具包，固件我已经打包好了放在网盘里面，兄弟们自取！</li></ul><blockquote><p>📺 视频教程：<br><a href="https://youtu.be/C6wuJbOT1sk" target="_blank" rel="noreferrer">点击观看 YouTube 视频教程</a></p></blockquote><p>小米BE3600刷机工具包：</p><p>仅需 ¥4.5元 <a href="/shop/mi-be3600.html">👉 立即购买</a>（网盘发货，收集固件录制视频不易感谢支持！）</p><p><img src="'+i+'" alt="CasaOS界面"></p><h2 id="一、降级开启ssh方法" tabindex="-1">一、降级开启SSH方法 <a class="header-anchor" href="#一、降级开启ssh方法" aria-label="Permalink to &quot;一、降级开启SSH方法&quot;">​</a></h2><p>BE3600买来就是最新的1.0.87版本（默认串口关闭），无法通过192.168.31.1后台降级固件，也无法通过网上的教程开启ssh并降级固件（下面有附带）。经过研究，终于发现可以通过下面方法搞定：</p><p>先说思路：在升级过程中断电，搞坏文件系统，路由器无法启动，再通过官方修复工具降级。</p><p>按照这个方法，我已成功将BE3600 2.5G v1.0.87版本降级到v1.0.81。</p><p>具体做法：</p><p>因为小米官方修复工具不能正常降级，会比较版本。所以只能用官方修复工具升级当前版本，也就是v1.0.87版本。 官方修复工具升级（小米路由器是双分区相互备份）：先升级root.ubi（第一分区系统），再升级backup of root.ubi（第二分区系统）</p><p>下面操作时机很重要 经过接了TTL线得出结论：在修复工具固件传输进度条结束后开始计时，12s左右断电（为了破坏第二分区系统），断电后需马上再次进入官方恢复流程，再次用修复工具升级， 第二次修复工具固件传输进度条结束后开始计时，5s左右断电（为了破坏第一分区系统）。</p><p>一定要按照先破坏OS2再破坏OS1顺序，这时OS1 ，OS2均被破坏。可以通过观察灯来确认路由器在不停重启。</p><p>接下来就可以通过官方修复工具进行降级了，三次修复工具升级，这次就用1.0.81固件，如果成功蓝灯闪烁，可以断电重启了，恭喜降级成功！如果橙色灯常亮，说明俩分区系统破坏不成功，肯定是断电时机不对。多试几次吧）。</p><p><img src="'+r+'" alt="CasaOS界面"></p><p>然后通过小米SSH开启工具成功打开ssh，跟着视频操作！</p><h2 id="二、刷入uboot和大分区表" tabindex="-1">二、刷入uboot和大分区表 <a class="header-anchor" href="#二、刷入uboot和大分区表" aria-label="Permalink to &quot;二、刷入uboot和大分区表&quot;">​</a></h2><p>使用到的工具：SSH连接工具</p><p>这里我就以MobaXterm工具为例，打开SSH工具，填入路由器管理后台地址，登录用户为root，点击 OK 确定即可。</p><p>Uboot分区默认在mtd14里面，我们直接刷入就行了</p><p>写入Uboot</p><p>将下载的uboot和大分区文件直接拖拽传输至tmp文件夹。</p><p>cd /tmp</p><p>先检查文件是否上传成功 ls -l /tmp/*.bin</p><p>验证MD5（可选） md5sum /tmp/xiaomi-be3600-mibib.bin md5sum /tmp/xiaomi-be3600-u-boot.mbn</p><p>#刷大分区</p><p>mtd write xiaomi-be3600-mibib.bin /dev/mtd2</p><p>#刷uboot</p><p>mtd write xiaomi-be3600-u-boot.mbn /dev/mtd14</p><p>刷入完成然后重启：</p><p>reboot</p><p>如果想恢复小米原厂系统可以使用下面命令恢复！</p><p>cd /tmp</p><p>mtd write mtd2_0MIBIB.bin /dev/mtd2</p><p>mtd write mtd14_0APPSBL.bin /dev/mtd14</p><p>然后就是重启再用小米救砖工具刷就好了。</p><h2 id="三、刷入openwrt固件" tabindex="-1">三、刷入OPENWRT固件 <a class="header-anchor" href="#三、刷入openwrt固件" aria-label="Permalink to &quot;三、刷入OPENWRT固件&quot;">​</a></h2><p>设置电脑IP为 192.168.1.2 掩码为 255.255.255.0</p><p>路由器进入Uboot用卡针顶住路由器reset键，之后路由器接入电源。reset键一直按住等待10秒左右，松开reset键。</p><p>浏览器登录192.168.1.1 ，即可进入Uboot页面，上传openwrt固件即可。</p><p><img src="'+s+'" alt="CasaOS界面"></p><p>OpenWrt</p><p>后台是192.168.1.1</p><p>账号root</p><p><img src="'+l+'" alt="CasaOS界面"></p><ul><li>收集整理不容易！给视频点赞关注就是对我最大的支持！</li></ul>',49)]))}const E=p(m,[["render",b]]);export{B as __pageData,E as default};
